addEventListener("fetch", (event: FetchEvent) => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request: Request): Promise<Response> {
  try {
    const url = new URL(request.url);
    const envPaths = Deno.env.get("PLUGIN_PATHS")?.split(",") ?? [];
    const queryPaths = url.searchParams.getAll("plugin");
    const modulePaths = [...envPaths, ...queryPaths];

    const results: unknown[] = [];
    for (const path of modulePaths) {
      try {
        const pluginModule = await import(path);
        if (typeof pluginModule.default === "function") {
          results.push(await pluginModule.default());
        } else {
          const pluginKeys = Object.keys(pluginModule);
          results.push({
            path,
            message: "Loaded but no default export found.",
            exports: pluginKeys,
          });
        }
      } catch (err) {
        results.push({ path, error: err.message });
      }
    }

    return new Response(JSON.stringify(results, null, 2), {
      headers: { "Content-Type": "application/json" },
    });
  } catch (error) {
    return new Response(error?.message ?? "Unknown error", { status: 500 });
  }
}